var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"휘유, 역시 카운터가 있으니 다르구만.","JPN":"ほう、さすがカウンターだな。","ENG":"Whew... Having a Counter really does make a big difference.","TWN":"哇，有制裁者在就是不一樣呢！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"잔챙이들 상대하는 소탕 작전이라지만, 승차감이 달라.","JPN":"雑魚相手の掃討作戦だとはいえ、安心感が違う。","ENG":"Even if we're just clearing out goons, it's way easier now.","TWN":"雖然只是掃蕩小嘍囉的作戰，但感覺完全不一樣！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"하하. 아부하지 마. 잔챙이들뿐이었는데 뭐.","JPN":"ハハ。世辞はよせよ。雑魚だけだっただろ？","ENG":"Haha! Stop buttering her up. It was only small fish this time, anyway.","TWN":"哈哈，沒這麼誇張啦，不過就是些小嘍囉而已。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이것이 침식체들과의 싸움…!","JPN":"これが侵食体との戦い……！","ENG":"So this is what it's like to fight C.O.s...!","TWN":"這就是在對付侵蝕體…！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 노엘도 한 단계 성장한 기분이에요!","JPN":"私、ノエルも一段階成長した気分です！","ENG":"I feel like I'm learning so much!","TWN":"感覺洛艾兒我也成長了呢！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"하아…. 하나는 재수가 없고 하나는 쓸모가 없네.","JPN":"はあ……一人はムカつくやつで、一人は役立たずだ。","ENG":"*Sigh...* Guess one is just annoying and the other is useless.","TWN":"嘖…真是一點用也沒有。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"희한한 무기를 쓰길래 데려왔더니 구경만 하잖아. 견학생도 아니고.","JPN":"珍しい武器を使ってるから連れてきたのに、見てるだけじゃねえか。見学ツアーかよ。","ENG":"I let her tag along because she used a peculiar weapon, but all she's done is watch us fight. This isn't some field trip.","TWN":"我帶你來是要你使用那個稀奇的武器，結果你在旁邊看熱鬧，你又不是實習生。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으음~","JPN":"むむむ～","ENG":"Mm...","TWN":"呃呃～"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"뭘 그렇게 두리번거려? 긴장 풀어.","JPN":"何をそんなキョロキョロしてんだ？　ちょっとはリラックスしたらどうだ。","ENG":"What are you lookin' around like that for? Relax.","TWN":"在那邊東張西望什麼？放輕鬆。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"어차피 여긴 소탕 작전을 자주 해서 1종 침식체도 간간이 나타나는 구역이야.","JPN":"どうせここはよく掃討作戦が行われていて、第1種侵食体もたまにしか現れない区域なんだ。","ENG":"Because this place has frequent sweep operations done, even Category 1 C.O.s don't appear often anyway.","TWN":"這裡我們很常進行掃蕩作戰，連1類侵蝕體都很偶爾才會出現。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네에? 그럼 3종 침식체는 안 나타나요?","JPN":"ええ？　じゃあ、第3種侵食体は現れないんですか？","ENG":"Whaaat? Then Category 3 C.O.s don't appear around here?","TWN":"什麼？那3類侵蝕體也不會出現囉？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"3종 침식체?","JPN":"第3種侵食体？","ENG":"A Category 3 C.O.?","TWN":"3類侵蝕體？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"아이구, 요새 애들이 넷튜브로 용병질 배운다더니 진짜였네.","JPN":"やれやれ、最近の子はネットチューブで傭兵の仕事を教わるって聞いたが、本当だったんだな。","ENG":"Oof, I guess it's true that kids these days learned about mercenaries through NetTube.","TWN":"哇，我聽說最近的人都是上網看影片自學當傭兵的，沒想到是真的。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"왜 그러세요? 제가 뭐 잘못 말했어요?","JPN":"どうしたんですか？　何か変なことでも言いました？","ENG":"Why do you say that? Did I say something wrong?","TWN":"幹嘛這樣？我有說錯什麼嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"야, 재수 없는 소리 하지 마. 듣기도 싫다.","JPN":"おい、縁起の悪いこと言うなよ。聞きたくもねえ。","ENG":"Hey, don't jinx it, all right? I don't wanna hear it.","TWN":"呸呸呸，你少說那些不吉利的話！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"비스트 같은 게 뜨기라도 하면 우린 그냥 죽은 목숨이라고.","JPN":"ビーストなんか現れでもしたら、俺らは死んだも同然だぞ。","ENG":"If something like a Beast really does show up, we're all dead meat.","TWN":"要是出現魔獸的話，我們可是會小命不保的。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히잉…. 어쩌죠. 펜릴 소대에 들어오고 싶으면 3종 침식체를 잡아야 한다던데.","JPN":"ふえん……どうしましょう。フェンリル小隊に入りたかったら、第3種侵食体を捕まえないとダメって言われたのに。","ENG":"Hnnnggg... But I need to defeat one if I want to become a member of Fenrir Squad.","TWN":"嗚嗚…怎麼辦？要抓到3類侵蝕體我才能進芬里爾小隊欸。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"펜릴 소대? 그거 관리국에 찍혔다던 태스크포스 소속 아니야?","JPN":"フェンリル小隊？　そりゃ、管理局に目つけられたっていうタスクフォースの所属じゃねえか？","ENG":"Fenrir Squad? Isn't that the TASKFORCE that's on the Administration's blacklist?","TWN":"芬里爾小隊？那不是被管理局盯上的特遣勢力嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"요즘 애들답지 않게 순진하네. 그거 보나마나 허세야, 허세.","JPN":"今時の子にしちゃ、純粋だな。あんなのただのはったりだよ。はったり。","ENG":"Geez, kids these days are naive. You know they're all just talk, right?","TWN":"你還真單純，想也知道那是唬你的啦。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"허세라니 그럴 리가요. 유미나 님이 얼마나 멋진 분인데요.","JPN":"そんなはずありませんよ。ミナ様は本当にカッコいい方なんです。","ENG":"They're not all talk. Ms. Mina is the real deal.","TWN":"才不是唬我的呢！劉米娜小姐超棒的。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 과제를 통과해서 꼭 유미나 님이랑 같은 소대가 될 거예요!","JPN":"この課題に合格して、絶対にミナ様と同じ小隊になるんですから！","ENG":"I'm going to complete my assignment and join Ms. Mina's squad!","TWN":"我一定會通過這個測驗，和劉米娜小姐同一個小隊！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"이거 중증이네. 안 되겠어.","JPN":"こりゃあ、重症だ。ダメだな。","ENG":"She's helpless. There's nothing we can do.","TWN":"糟糕，她病得不輕欸。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"사회 경험이 없어서 그렇지.","JPN":"社会経験がないからだろ。","ENG":"She's just inexperienced, that's all.","TWN":"她社會經驗還不夠吧。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"애초에 그런 구멍가게 같은 태스크포스가 특수 부대랑 같이 일한다는 게 말이 돼?","JPN":"大体、あんな小っちゃいタスクフォースが特殊部隊と一緒に働くってあり得ねえだろ。","ENG":"Think about it. In what universe would special forces like Delta Seven team up with a tiny TASKFORCE like that anyway?","TWN":"想也知道，那種名不見經傳的特遣勢力，怎麼可能和特殊部隊一起作戰，合理嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"어이, 친구들. 저쪽 무너진 빌딩 뒤에서 침식 쐐기를 하나 찾았어.","JPN":"おい。あっちの崩れたビルから侵食楔を一つ見つけたぞ。","ENG":"Hey, guys? I found a Corrupted Wedge behind that collapsed building over there.","TWN":"喂，我在那邊倒塌的大樓後面找到一個侵蝕釘。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"오, 이거 오늘은 일복이 좀 텄나?","JPN":"お、こりゃあ、今日はじゃんじゃん稼げるんじゃないか？","ENG":"Ooh, guess we're pretty lucky today, eh?","TWN":"哇喔，今天的工作運不錯喔？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"의뢰를 수락한 보람이 생겼네. 다른 놈들이 선수 치기 전에 어서 가자고.","JPN":"依頼を受け入れた甲斐があるな。他のやつらに先越される前に早く行こうぜ。","ENG":"Guess it paid off to accept this job. C'mon, let's go get it before someone else does first.","TWN":"看來今天接這個委託有值得了。快走吧，否則到時候被別人搶先。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗?! 잠시만요! 저도 같이 가요!","JPN":"あっ！？　待ってください！　私も一緒に行きますよ！","ENG":"Huh!? Wait up! Take me with you!","TWN":"嗯？！等等我！我也一起去！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};